{"id":"go:tpl/tplimpl/templatestore.go#LookupPagesLayout@584","source":"func (s *TemplateStore) LookupPagesLayout(q TemplateQuery) *TemplInfo {
	q.init()
	key := s.key(q.Path)

	slashCountKey := strings.Count(key, "/")
	best1 := s.getBest()
	defer s.putBest(best1)
	s.findBestMatchWalkPath(q, key, slashCountKey, best1)
	if best1.w.w1 <= 0 {
		return nil
	}
	m := best1.templ
	if m.noBaseOf {
		return m
	}
	best1.reset()
	m.findBestMatchBaseof(s, q.Desc, q.Sites, key, slashCountKey, best1)
	if best1.w.w1 <= 0 {
		return nil
	}

	return best1.templ
}"}

